import{_ as t,o as d,c as a,ag as r}from"./chunks/framework.Vng7Hdlh.js";const m=JSON.parse('{"title":"AI Tools","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/ai-tools.md","filePath":"admin-ui/ai-tools.md"}'),o={name:"admin-ui/ai-tools.md"};function s(i,e,l,n,c,h){return d(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="ai-tools" tabindex="-1">AI Tools <a class="header-anchor" href="#ai-tools" aria-label="Permalink to &quot;AI Tools&quot;">​</a></h1><p>The AI Tools page manages MCP (Model Context Protocol) servers, the built-in MCP endpoint, and AI skill packages. These tools power the admin AI chat assistant and can be exposed to external MCP clients.</p><h2 id="accessing" tabindex="-1">Accessing <a class="header-anchor" href="#accessing" aria-label="Permalink to &quot;Accessing&quot;">​</a></h2><p>Navigate to <strong>AI Tools</strong> in the admin sidebar. The page has three tabs:</p><h2 id="mcp-servers-tab" tabindex="-1">MCP Servers Tab <a class="header-anchor" href="#mcp-servers-tab" aria-label="Permalink to &quot;MCP Servers Tab&quot;">​</a></h2><p>Manages connections to external MCP servers that provide additional tools to the AI assistant.</p><h3 id="server-list" tabindex="-1">Server List <a class="header-anchor" href="#server-list" aria-label="Permalink to &quot;Server List&quot;">​</a></h3><p>Displays all configured MCP servers with:</p><ul><li>Server name and URL</li><li>Type badge — <code>internal</code> (from templates) or <code>external</code> (dynamically added)</li><li>Connection status — <code>connected</code>, <code>disconnected</code>, <code>error</code>, <code>unknown</code></li><li>Tool count</li><li>Last health check timestamp</li></ul><h3 id="adding-a-server" tabindex="-1">Adding a Server <a class="header-anchor" href="#adding-a-server" aria-label="Permalink to &quot;Adding a Server&quot;">​</a></h3><p><strong>From Template Gallery</strong> — Browse pre-configured MCP server templates organized by category (Healthcare, Development, Data, etc.). Click a template to install with pre-filled configuration.</p><p><strong>Custom Server</strong> — Click <strong>Add Server</strong> to configure a custom MCP server:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Unique identifier for the server</td></tr><tr><td><strong>URL</strong></td><td>MCP server endpoint URL (Streamable HTTP)</td></tr><tr><td><strong>Description</strong></td><td>Optional description of the server&#39;s capabilities</td></tr></tbody></table><h3 id="server-operations" tabindex="-1">Server Operations <a class="header-anchor" href="#server-operations" aria-label="Permalink to &quot;Server Operations&quot;">​</a></h3><ul><li><strong>Health Check</strong> — Test connectivity and retrieve server capabilities</li><li><strong>View Tools</strong> — List all tools exposed by the server with their input schemas</li><li><strong>Refresh All</strong> — Re-check health of all configured servers</li><li><strong>Delete</strong> — Remove a dynamically added server</li></ul><h3 id="registry-search" tabindex="-1">Registry Search <a class="header-anchor" href="#registry-search" aria-label="Permalink to &quot;Registry Search&quot;">​</a></h3><p>Search the public MCP server registry to discover and install community servers. Results show server name, description, and install action.</p><h3 id="server-persistence" tabindex="-1">Server Persistence <a class="header-anchor" href="#server-persistence" aria-label="Permalink to &quot;Server Persistence&quot;">​</a></h3><p>Server configuration is stored in <code>mcp.json</code> alongside the backend. Template servers come from <code>mcp-server-templates.json</code>.</p><h2 id="mcp-endpoint-tab" tabindex="-1">MCP Endpoint Tab <a class="header-anchor" href="#mcp-endpoint-tab" aria-label="Permalink to &quot;MCP Endpoint Tab&quot;">​</a></h2><p>Configures the built-in MCP endpoint that exposes Proxy Smart&#39;s own backend tools as an MCP server.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enabled</strong></td><td>Whether the MCP endpoint is active (enabled by default)</td></tr><tr><td><strong>Path</strong></td><td>URL path for the endpoint (default: <code>/mcp</code>)</td></tr></tbody></table><p>When enabled, external MCP clients (Claude Desktop, Cursor, etc.) can connect to <code>{BASE_URL}/mcp</code> and access all admin API tools via the MCP protocol. Authentication uses OAuth Bearer tokens with RFC 9728 discovery.</p><p>See <a href="./../MCP_HTTP_SERVER">MCP HTTP Server</a> for protocol details.</p><h2 id="skills-tab" tabindex="-1">Skills Tab <a class="header-anchor" href="#skills-tab" aria-label="Permalink to &quot;Skills Tab&quot;">​</a></h2><p>Manages AI skill packages — structured prompts and tool configurations that enhance the AI assistant&#39;s capabilities.</p><h3 id="installed-skills" tabindex="-1">Installed Skills <a class="header-anchor" href="#installed-skills" aria-label="Permalink to &quot;Installed Skills&quot;">​</a></h3><p>Lists currently installed skills with:</p><ul><li>Skill name and description</li><li>Source URL (e.g., GitHub repository)</li><li>Type — <code>claude-skill</code> or <code>custom</code></li><li>Install date</li><li>Enabled/disabled toggle</li></ul><h3 id="adding-skills" tabindex="-1">Adding Skills <a class="header-anchor" href="#adding-skills" aria-label="Permalink to &quot;Adding Skills&quot;">​</a></h3><p><strong>From Registry</strong> — Browse and search the skills.sh registry for community skills. Click install to add a skill.</p><p><strong>Custom Skill</strong> — Create a custom skill with a name and description.</p><h3 id="deleting-skills" tabindex="-1">Deleting Skills <a class="header-anchor" href="#deleting-skills" aria-label="Permalink to &quot;Deleting Skills&quot;">​</a></h3><p>Remove installed skills that are no longer needed. Built-in default skills can be re-installed from the registry.</p><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><h3 id="mcp-servers" tabindex="-1">MCP Servers <a class="header-anchor" href="#mcp-servers" aria-label="Permalink to &quot;MCP Servers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/mcp-servers/templates</code></td><td>List available server templates</td></tr><tr><td><code>GET</code></td><td><code>/admin/mcp-servers/</code></td><td>List all configured servers</td></tr><tr><td><code>GET</code></td><td><code>/admin/mcp-servers/:name/health</code></td><td>Check server health</td></tr><tr><td><code>GET</code></td><td><code>/admin/mcp-servers/:name/tools</code></td><td>List server tools</td></tr><tr><td><code>POST</code></td><td><code>/admin/mcp-servers/refresh</code></td><td>Refresh all server statuses</td></tr><tr><td><code>POST</code></td><td><code>/admin/mcp-servers/</code></td><td>Add a new server</td></tr><tr><td><code>PATCH</code></td><td><code>/admin/mcp-servers/:name</code></td><td>Update server configuration</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/mcp-servers/:name</code></td><td>Remove a server</td></tr><tr><td><code>GET</code></td><td><code>/admin/mcp-servers/registry/search</code></td><td>Search public registry</td></tr></tbody></table><h3 id="mcp-endpoint" tabindex="-1">MCP Endpoint <a class="header-anchor" href="#mcp-endpoint" aria-label="Permalink to &quot;MCP Endpoint&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/mcp-endpoint/</code></td><td>Get endpoint configuration</td></tr><tr><td><code>PATCH</code></td><td><code>/admin/mcp-endpoint/</code></td><td>Update endpoint settings</td></tr></tbody></table><h3 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/ai-tools/skills/</code></td><td>List installed skills</td></tr><tr><td><code>POST</code></td><td><code>/admin/ai-tools/skills/</code></td><td>Install a custom skill</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/ai-tools/skills/:name</code></td><td>Remove a skill</td></tr><tr><td><code>GET</code></td><td><code>/admin/ai-tools/skills/registry/browse</code></td><td>Browse skill registry</td></tr><tr><td><code>GET</code></td><td><code>/admin/ai-tools/skills/registry/search</code></td><td>Search skill registry</td></tr><tr><td><code>POST</code></td><td><code>/admin/ai-tools/skills/registry/install</code></td><td>Install from registry</td></tr></tbody></table><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>OPENAI_API_KEY</code></td><td>API key for AI model access (enables AI features)</td><td>—</td></tr><tr><td><code>AI_TIMEOUT_MS</code></td><td>AI request timeout in milliseconds</td><td><code>30000</code></td></tr><tr><td><code>MCP_ENDPOINT_ENABLED</code></td><td>Enable/disable MCP endpoint</td><td><code>true</code></td></tr><tr><td><code>MCP_ENDPOINT_PATH</code></td><td>URL path for MCP endpoint</td><td><code>/mcp</code></td></tr></tbody></table>',43)])])}const b=t(o,[["render",s]]);export{m as __pageData,b as default};
